// Ground base: meadow, dirt path, pebbles (renders behind cyclist)
export function GroundBase(): ReactNode {
  return (
    <svg
      width="100%"
      height="100%"
      viewBox="0 0 1600 400"
      preserveAspectRatio="none"
      shapeRendering="crispEdges"
      xmlns="http://www.w3.org/2000/svg"
      className="absolute -bottom-px w-full h-[102%]"
    >
      {/* Meadow background */}
      <path
        d="M 0 120 C 300 120, 500 80, 800 150 C 1100 220, 1400 120, 1600 120 L 1600 1200 L 0 1200 Z"
        style={{ fill: 'var(--scene-ground)' }}
      />

      {/* Higher Dirt Path */}
      <path
        d="M 0 70 Q 400 120, 800 60 T 1600 70 L 1600 240 Q 1200 280, 800 250 T 0 240 Z"
        style={{ fill: 'var(--scene-path)' }}
      />

      {/* Path pebbles scattered across the dirt track */}
      <g style={{ fill: 'var(--scene-pebble)' }}>
        <ellipse cx="120" cy="110" rx="10" ry="3.5" />
        <ellipse cx="180" cy="160" rx="5" ry="2" />
        <ellipse cx="450" cy="140" rx="8" ry="3" />
        <ellipse cx="550" cy="200" rx="14" ry="5" />
        <ellipse cx="850" cy="130" rx="12" ry="4" />
        <ellipse cx="1050" cy="150" rx="7" ry="2" />
        <ellipse cx="1300" cy="140" rx="9" ry="3" />
        <ellipse cx="1380" cy="190" rx="6" ry="2.5" />
      </g>
    </svg>
  )
}

